<span class="line"><span style="color:#66D9EF;font-style:italic;">def</span><span style="color:#A6E22E;"> is_finished</span><span style="color:#F8F8F2;">(</span><span style="color:#FD971F;font-style:italic;">board</span><span style="color:#F8F8F2;">: list[list[Ship </span><span style="color:#F92672;">|</span><span style="color:#AE81FF;"> None</span><span style="color:#F8F8F2;">]]):</span></span>
